// packages/ui/flutter/lib/src/components/organisms/direction/direction.widget.dart
/// BTDirection — form panel organism with header, content slot, footer.
/// Figma source: node 2504-3364.
///
/// Stateless layout container. Caller owns all interaction logic.
///
/// ## Usage:
/// ```dart
/// BTDirection(
///   title: 'Edit Profile',
///   subtext: 'Update your information below.',
///   linkLabel: 'Need help?',
///   primaryLabel: 'Save changes',
///   secondaryLabel: 'Cancel',
///   onPrimaryPressed: handleSave,
///   onSecondaryPressed: handleCancel,
///   onLinkPressed: openHelp,
///   child: Column(
///     children: [
///       BTInput(label: 'Name', ...),
///       BTInput(label: 'Email', ...),
///     ],
///   ),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import '../button-link/button_link.widget.dart';
import 'package:flutter/material.dart';

/// Form panel organism — header (title + optional subtext + optional link),
/// a content slot, and a footer with primary + optional secondary button.
class BTDirection extends StatelessWidget {
  const BTDirection({
    required this.title,
    required this.primaryLabel,
    required this.onPrimaryPressed,
    this.subtext,
    this.linkLabel,
    this.secondaryLabel,
    this.onSecondaryPressed,
    this.onLinkPressed,
    this.child,
    super.key,
  });

  /// Bold heading in the header (18 sp).
  final String title;

  /// Supporting text below the title. Hidden when null.
  final String? subtext;

  /// Label for the optional top-right link. Hidden when null.
  final String? linkLabel;

  /// Label for the primary footer button (brand, full-width).
  final String primaryLabel;

  /// Label for the secondary footer button (neutral, full-width).
  /// Hidden when null.
  final String? secondaryLabel;

  /// Callback for the primary footer button.
  final VoidCallback onPrimaryPressed;

  /// Callback for the secondary footer button. Hidden when null.
  final VoidCallback? onSecondaryPressed;

  /// Callback for the top-right link. Hidden when null.
  final VoidCallback? onLinkPressed;

  /// Content placed in the slot between the header row and footer.
  final Widget? child;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final r = context.btRadius;

    return ClipRRect(
      borderRadius: BorderRadius.circular(r.md),
      child: DecoratedBox(
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(r.md),
          boxShadow: BTShadow.elevation.md,
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // ── White header section ────────────────────────────────────────
            Container(
              color: c.bg.primary,
              padding: EdgeInsets.all(16.0),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  // Header row: title block + optional link
                  Row(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Expanded(
                        child: Column(
                          mainAxisSize: MainAxisSize.min,
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              title,
                              style: TextStyle(
                                fontSize: 18.0,
                                fontWeight: FontWeight.w700,
                                height: 24 / 18,
                                color: c.text.primary,
                                fontFamily: BTTypography.fontFamily,
                              ),
                            ),
                            if (subtext != null) ...[
                              SizedBox(height: 4.0),
                              Text(
                                subtext!,
                                style: TextStyle(
                                  fontSize: 14.0,
                                  fontWeight: FontWeight.w500,
                                  height: 16 / 14,
                                  color: c.text.secondary,
                                  fontFamily: BTTypography.fontFamily,
                                ),
                              ),
                            ],
                          ],
                        ),
                      ),
                      if (onLinkPressed != null && linkLabel != null) ...[
                        SizedBox(width: 10.0),
                        BTButtonLink(
                          label: linkLabel!,
                          onPressed: onLinkPressed,
                        ),
                      ],
                    ],
                  ),
                  // Content slot
                  if (child != null) ...[
                    SizedBox(height: 16.0),
                    child!,
                  ],
                ],
              ),
            ),
            // ── Grey footer section ─────────────────────────────────────────
            Container(
              color: c.bg.subtle,
              padding: EdgeInsets.all(16.0),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  BTButton(
                    label: primaryLabel,
                    onPressed: onPrimaryPressed,
                  ),
                  if (onSecondaryPressed != null && secondaryLabel != null) ...[
                    SizedBox(height: 8.0),
                    BTButton(
                      label: secondaryLabel!,
                      variant: BTButtonVariant.secondaryLight,
                      onPressed: onSecondaryPressed,
                    ),
                  ],
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }
}
